40: function parseArgs(argv) {
41:   const args = {};
42:   for (const entry of argv) {
43:     if (!entry.startsWith('--')) {
44:       continue;
45:     }
46:     const [key, ...rest] = entry.slice(2).split('=');
47:     args[key] = rest.length > 0 ? rest.join('=') : true;
48:   }
49:   return args;
50: }
