52: function readUtf8(filePath) {
53:   return fs.readFileSync(filePath, 'utf8');
54: }
55: 
56: function writeJson(filePath, value) {
57:   fs.mkdirSync(path.dirname(filePath), { recursive: true });
58:   fs.writeFileSync(filePath, `${JSON.stringify(value, null, 2)}\n`, 'utf8');
59: }
60: 
61: // 015 P2 (dedup): dedupe the repeated infra-failure emission. Each early-exit failure site built the
62: // same infra_failure object and ran the identical outputPath/writeJson/stdout/exit branch.
63: // emitInfraFailure centralizes the standard fields plus the write-or-stdout + exit code,
64: // taking only the per-site variable fields.
65: function emitInfraFailure(outputPath, fields) {
66:   const failure = {
67:     status: 'infra_failure',
68:     evaluationMode: 'dynamic-5d',
69:     mode: 'agent-improvement',
70:     ...fields,
71:   };
72:   if (outputPath) {
73:     writeJson(outputPath, failure);
74:   } else {
75:     process.stdout.write(`${JSON.stringify(failure, null, 2)}\n`);
76:   }
77:   process.exit(1);
78: }
