80: function stableJson(value) {
81:   if (Array.isArray(value)) {
82:     return `[${value.map((entry) => stableJson(entry)).join(',')}]`;
83:   }
84:   if (value && typeof value === 'object') {
85:     return `{${Object.keys(value)
86:       .sort()
87:       .map((key) => `${JSON.stringify(key)}:${stableJson(value[key])}`)
88:       .join(',')}}`;
89:   }
90:   return JSON.stringify(value);
91: }
92: 
93: function stripVolatileFields(value) {
94:   if (Array.isArray(value)) {
95:     return value.map((entry) => stripVolatileFields(entry));
96:   }
97:   if (value && typeof value === 'object') {
98:     const result = {};
99:     for (const [key, entry] of Object.entries(value)) {
100:       if (key === 'timestamp' || key === 'generatedAt') {
101:         continue;
102:       }
103:       result[key] = stripVolatileFields(entry);
104:     }
105:     return result;
106:   }
107:   return value;
108: }
