124: function loadManifest(manifestPath) {
125:   if (!manifestPath) {
126:     return null;
127:   }
128:   const raw = safeRead(manifestPath);
129:   if (typeof raw !== 'string') {
130:     return { error: raw.error };
131:   }
132:   try {
133:     return JSON.parse(stripJsonComments(raw));
134:   } catch (error) {
