139: function inferProfileId(targetPath, explicitProfile, manifest) {
140:   if (explicitProfile) {
141:     return explicitProfile;
142:   }
143:   const manifestTarget = manifest?.targets?.find((entry) => entry.path === targetPath);
144:   if (manifestTarget?.profileId) {
145:     return manifestTarget.profileId;
146:   }
147:   return 'dynamic';
