170: const RUBRIC_VERSION = 'dynamic-5d/p126-reproducibility-v1';
171: 
172: // F-P1-11: scope the score cache under a packet-local directory rather than a shared,
173: // world-writable os.tmpdir() location whose contents are trusted before rescoring.
174: // Prefer the --output directory (the canonical packet-local outputs dir), then the
175: // candidate's own directory; only fall back to os.tmpdir() when neither is available.
176: function defaultCacheDir({ outputPath, candidatePath } = {}) {
177:   const anchorDir = outputPath
178:     ? path.dirname(path.resolve(outputPath))
179:     : candidatePath
180:       ? path.dirname(path.resolve(candidatePath))
181:       : null;
182:   if (anchorDir) {
183:     return path.join(anchorDir, '.score-cache');
184:   }
185:   return path.join(os.tmpdir(), 'deep-improvement-score-cache');
186: }
187: 
188: function computeInputHash(input) {
189:   return crypto
190:     .createHash('sha256')
191:     .update(stableJson(input))
192:     .digest('hex');
193: }
194: 
195: function cachePathFor(cacheDir, inputHash) {
196:   return path.join(cacheDir, `${inputHash}.json`);
197: }
198: 
199: // F017-P2-10 (017 review): the filename is the only thing binding a cache entry to its
200: // inputHash. Treat the embedded blob as untrusted on read: require cached.inputHash to
201: // equal the recomputed inputHash AND a scored status. Any mismatch (tampered or stale
202: // blob, wrong-key file dropped into the cache dir, parse failure) is a cache MISS so the
203: // caller recomputes rather than trusting an unverified payload.
204: function readCachedScore(cacheDir, inputHash) {
205:   const cachePath = cachePathFor(cacheDir, inputHash);
206:   if (!fs.existsSync(cachePath)) {
207:     return null;
208:   }
209:   let cached;
210:   try {
211:     cached = JSON.parse(fs.readFileSync(cachePath, 'utf8'));
212:   } catch (_err) {
213:     return null;
214:   }
215:   if (!cached || typeof cached !== 'object') {
216:     return null;
217:   }
218:   if (cached.inputHash !== inputHash || cached.status !== 'scored') {
219:     return null;
220:   }
221:   return cached;
222: }
223: 
224: function writeCachedScore(cacheDir, inputHash, result) {
225:   writeJson(cachePathFor(cacheDir, inputHash), result);
226: }
