228: function runScript(scriptName, args) {
229:   const scriptPath = path.join(__dirname, scriptName);
230:   try {
231:     const out = execFileSync('node', [scriptPath, ...args], { encoding: 'utf8', timeout: 15000 });
232:     try {
233:       return JSON.parse(out);
234:     } catch (err) {
235:       return serializeTypedError(makeTypedError(ERROR_TYPES.PARSE_ERROR, `Failed to parse ${scriptName} output: ${err.message}`, { scriptName }));
236:     }
237:   } catch (err) {
238:     const childError = parseTypedError(err.stderr);
239:     if (childError) {
240:       return childError;
241:     }
242:     const errorType = err.status === EXIT_CODES[ERROR_TYPES.FILE_NOT_FOUND]
243:       ? ERROR_TYPES.FILE_NOT_FOUND
244:       : ERROR_TYPES.SCRIPT_CRASH;
245:     return serializeTypedError(makeTypedError(errorType, `${scriptName} failed: ${err.message}`, { scriptName, status: err.status || null }));
246:   }
247: }
