249: function scoreDimStructural(profile, content) {
250:   const checks = profile.derivedChecks?.structural || [];
251:   if (checks.length === 0) { return { score: null, details: [], maxPossible: 0, unscored: true }; }
252:   const maxPossible = checks.reduce((s, c) => s + c.weight, 0);
253:   let earned = 0;
254:   const details = [];
255:   for (const check of checks) {
256:     const sectionName = check.description.replace('Agent has ', '').replace(' section', '').toUpperCase();
257:     const pass = new RegExp(`## \\d+\\.\\s+.*${sectionName.split(' ')[0]}`, 'i').test(content);
258:     if (pass) { earned += check.weight; }
259:     details.push({ id: check.id, pass, weight: check.weight });
260:   }

