  const result = {
    status: 'scored',
    rubricVersion: RUBRIC_VERSION,
    inputHash,
    profileId: resolvedProfileId,
    family: family || profile.family,
    evaluationMode: 'dynamic-5d',
    mode: 'agent-improvement',
