  if (!cacheDisabled) {
    writeCachedScore(cacheDir, inputHash, result);
  }

  if (outputPath) {
    writeJson(outputPath, result);
  } else {
    process.stdout.write(`${JSON.stringify(result, null, 2)}\n`);
  }
}

